package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.lang.reflect.Field;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.sail.NotifyingSailConnection;
import org.eclipse.rdf4j.sail.base.SketchBasedJoinEstimator;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbSailStoreEstimatorPersistenceTest {

	private static final String SNAPSHOT_FILE = "join-estimator.rjes";

	@Test
	void closeWritesEstimatorSnapshotAndReopensLazy(@TempDir File dataDir) throws Exception {
		var vf = SimpleValueFactory.getInstance();
		var s = vf.createIRI("urn:s");
		var p = vf.createIRI("urn:p");
		var o = vf.createIRI("urn:o");

		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc"));
		store.init();
		try {
			try (NotifyingSailConnection conn = store.getConnection()) {
				conn.begin();
				conn.addStatement(s, p, o);
				conn.commit();
			}
		} finally {
			store.shutDown();
		}

		assertTrue(new File(dataDir, SNAPSHOT_FILE).isFile(), "Expected estimator snapshot file after shutdown");

		LmdbStore reopened = new LmdbStore(dataDir, new LmdbStoreConfig("spoc"));
		reopened.init();
		try {
			LmdbSailStore backingStore = reopened.getBackingStore();
			SketchBasedJoinEstimator estimator = backingStore.getSketchBasedJoinEstimator();
			estimator.setLowMemorySupplier(() -> false);

			Field loadedField = SketchBasedJoinEstimator.class.getDeclaredField("sketchesLoaded");
			loadedField.setAccessible(true);
			assertFalse(loadedField.getBoolean(estimator), "Expected lazy startup with unloaded sketches");
			assertDoesNotThrow(estimator::isReady);
		} finally {
			reopened.shutDown();
		}
	}
}
